'use client';

import { useState, useEffect } from 'react';
import { db } from '@/lib/firebase';
import { collection, getDocs } from 'firebase/firestore';
import LZString from 'lz-string';
import {
    Store, Building2, Search, X, RefreshCw, CheckCircle2,
    Clock, AlertTriangle, TrendingUp, Users, Package,
    FileText, MapPin, Phone, Mail, Calendar, DollarSign,
    Filter, Download, Eye, ChevronDown, BarChart3, Bell, BellOff,
    Wifi, WifiOff, Star,
} from 'lucide-react';

type StoreEntry = {
    docId: string;
    email: string;
    name: string;
    phone: string;
    plan: string;
    registeredAt: string;
    lastActive: string;
    companiesCount: number;
    invoicesCount: number;
    companies: { id: string; name: string; type: string; city?: string; invoices: number }[];
    isActive: boolean;
    daysInactive: number;
    revenue: number;
};

const getPlanBadge = (plan: string) => {
    const p = plan?.toLowerCase();
    if (p === 'premium') return { bg: '#FEF3C7', color: '#D97706', label: '⭐ Premium' };
    if (p === 'standard') return { bg: '#E0E7FF', color: '#4338CA', label: '🔵 Standard' };
    if (p === 'expired_subscription' || p === 'expired') return { bg: '#FEE2E2', color: '#991B1B', label: '❌ Expired' };
    return { bg: '#F1F5F9', color: '#475569', label: '🆓 Free Trial' };
};

const getActivityStatus = (daysInactive: number) => {
    if (daysInactive === 0) return { color: '#10B981', label: 'Active Today', icon: '🟢' };
    if (daysInactive <= 3) return { color: '#3B82F6', label: `${daysInactive}d ago`, icon: '🔵' };
    if (daysInactive <= 14) return { color: '#F59E0B', label: `${daysInactive}d idle`, icon: '🟡' };
    return { color: '#EF4444', label: `${daysInactive}d inactive`, icon: '🔴' };
};

export default function RegisteredStoresPage() {
    const [loading, setLoading] = useState(true);
    const [stores, setStores] = useState<StoreEntry[]>([]);
    const [search, setSearch] = useState('');
    const [filter, setFilter] = useState<'all' | 'active' | 'inactive' | 'paid' | 'free' | 'new'>('all');
    const [expandedId, setExpandedId] = useState<string | null>(null);
    const [stats, setStats] = useState({ total: 0, active: 0, paid: 0, newThisWeek: 0, totalRevenue: 0 });
    const [notifications, setNotifications] = useState<{ id: string; msg: string; type: 'new' | 'inactive' | 'expired' }[]>([]);
    const [showNotifications, setShowNotifications] = useState(false);

    useEffect(() => {
        fetchStores();
    }, []);

    const fetchStores = async () => {
        setLoading(true);
        try {
            const snap = await getDocs(collection(db, 'userStores'));
            const list: StoreEntry[] = [];
            const notifs: typeof notifications = [];
            let totalPaid = 0, totalActive = 0, newThisWeek = 0;

            const now = Date.now();
            const oneWeek = 7 * 24 * 60 * 60 * 1000;

            snap.forEach((docSnap) => {
                const data = docSnap.data();
                let state: any = {};
                if (data.compressedState) {
                    try { state = JSON.parse(LZString.decompressFromUTF16(data.compressedState) || '{}'); } catch { }
                } else if (data.stateString) {
                    try { state = JSON.parse(data.stateString); } catch { }
                }

                const userObj = typeof state.user === 'object' && state.user ? state.user : {};
                const plan = userObj.subscriptionType || userObj.plan || 'free';
                const invoices: any[] = state.invoices || [];
                const companies: any[] = state.companies || [];

                const updatedAt = data.updatedAt ? new Date(data.updatedAt).getTime() : 0;
                const daysSinceActive = updatedAt ? Math.floor((now - updatedAt) / (1000 * 60 * 60 * 24)) : 999;
                const isActive = daysSinceActive <= 7;
                const isNew = updatedAt && (now - updatedAt) < oneWeek;

                const isPaid = plan !== 'free' && plan !== 'Free Trial' && plan !== 'expired_subscription';
                if (isPaid) totalPaid++;
                if (isActive) totalActive++;
                if (isNew) newThisWeek++;

                // Map companies
                const mappedCompanies = companies.map((co: any) => ({
                    id: co.id,
                    name: co.name || 'Unnamed',
                    type: co.type || 'N/A',
                    city: co.city || '',
                    invoices: invoices.filter((i: any) => i.companyId === co.id).length,
                }));

                const revenue = invoices.reduce((sum: number, inv: any) => sum + (inv.total || 0), 0);

                // Notifications
                if (isNew) notifs.push({ id: docSnap.id, msg: `New store registered: ${userObj.name || data.email || docSnap.id}`, type: 'new' });
                if (daysSinceActive > 30) notifs.push({ id: docSnap.id + '_inactive', msg: `Store inactive 30+ days: ${userObj.name || data.email}`, type: 'inactive' });
                if (plan === 'expired_subscription') notifs.push({ id: docSnap.id + '_exp', msg: `Expired plan: ${userObj.name || data.email}`, type: 'expired' });

                list.push({
                    docId: docSnap.id,
                    email: userObj.email || data.email || 'N/A',
                    name: userObj.name || data.email || 'Unknown',
                    phone: userObj.phone || 'N/A',
                    plan,
                    registeredAt: data.createdAt || data.updatedAt || '',
                    lastActive: data.updatedAt || '',
                    companiesCount: companies.length,
                    invoicesCount: invoices.length,
                    companies: mappedCompanies,
                    isActive,
                    daysInactive: daysSinceActive,
                    revenue,
                });
            });

            setStores(list.sort((a, b) => b.daysInactive - a.daysInactive === 0 ? 0 : a.daysInactive - b.daysInactive));
            setStats({ total: list.length, active: totalActive, paid: totalPaid, newThisWeek, totalRevenue: list.reduce((s, x) => s + x.revenue, 0) });
            setNotifications(notifs.slice(0, 20));
        } catch (err) {
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    const filtered = stores.filter(s => {
        const q = search.toLowerCase();
        const matchSearch = !q || s.name.toLowerCase().includes(q) || s.email.toLowerCase().includes(q) || s.phone.includes(q) || s.docId.includes(q);
        const matchFilter =
            filter === 'all' ? true :
            filter === 'active' ? s.isActive :
            filter === 'inactive' ? !s.isActive :
            filter === 'paid' ? (s.plan !== 'free' && s.plan !== 'Free Trial' && s.plan !== 'expired_subscription') :
            filter === 'free' ? (s.plan === 'free' || s.plan === 'Free Trial') :
            filter === 'new' ? s.daysInactive <= 7 : true;
        return matchSearch && matchFilter;
    });

    const exportCSV = () => {
        const rows = [['Name', 'Email', 'Phone', 'Plan', 'Companies', 'Invoices', 'Last Active', 'Status']];
        filtered.forEach(s => rows.push([s.name, s.email, s.phone, s.plan, String(s.companiesCount), String(s.invoicesCount), s.lastActive ? new Date(s.lastActive).toLocaleDateString() : 'N/A', s.isActive ? 'Active' : 'Inactive']));
        const csv = rows.map(r => r.join(',')).join('\n');
        const a = document.createElement('a'); a.href = 'data:text/csv;charset=utf-8,' + encodeURIComponent(csv); a.download = `stores_${Date.now()}.csv`; a.click();
    };

    return (
        <div style={{ maxWidth: 1200, margin: '0 auto' }}>
            <style>{`
                .stores-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(140px,1fr)); gap: 16px; margin-bottom: 32px; }
                .filter-bar { display: flex; gap: 8px; flex-wrap: wrap; margin-bottom: 20px; }
                .store-row { background: white; border-radius: 16px; border: 1px solid #F1F5F9; box-shadow: 0 2px 8px rgba(0,0,0,0.04); overflow: hidden; transition: box-shadow 0.2s; }
                .store-row:hover { box-shadow: 0 6px 24px rgba(0,0,0,0.08); }
                .store-header { display: flex; align-items: center; gap: 14px; padding: 16px 20px; cursor: pointer; flex-wrap: wrap; }
                .expand-section { background: #F8FAFC; border-top: 1px solid #F1F5F9; padding: 16px 20px; }
                .stat-chip { padding: 6px 12px; border-radius: 99px; font-size: 11px; font-weight: 700; display: inline-flex; align-items: center; gap: 4px; }
                .notif-panel { position: absolute; right: 0; top: 42px; width: 340px; background: white; border-radius: 16px; border: 1px solid #E2E8F0; box-shadow: 0 16px 48px rgba(0,0,0,0.12); z-index: 200; overflow: hidden; }
                @media (max-width: 639px) {
                    .stores-grid { grid-template-columns: repeat(2,1fr); }
                    .store-header { gap: 10px; padding: 12px 14px; }
                    .notif-panel { width: 280px; right: 0; }
                }
            `}</style>

            {/* Page Header */}
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 28, gap: 16, flexWrap: 'wrap' }}>
                <div>
                    <h1 style={{ fontSize: 28, fontWeight: 900, color: '#1A1A2E', display: 'flex', alignItems: 'center', gap: 10 }}>
                        <Store size={28} color="#4285F4" /> Registered Stores
                    </h1>
                    <p style={{ color: '#64748B', fontSize: 13, marginTop: 4 }}>Monitor all registered stores, activity status, and plan health.</p>
                </div>
                <div style={{ display: 'flex', gap: 8, alignItems: 'center', flexWrap: 'wrap' }}>
                    <button onClick={fetchStores} className="btn btn-outline" style={{ gap: 6, height: 40 }}><RefreshCw size={15} /> Refresh</button>
                    <button onClick={exportCSV} className="btn btn-outline" style={{ gap: 6, height: 40 }}><Download size={15} /> Export CSV</button>
                    <div style={{ position: 'relative' }}>
                        <button onClick={() => setShowNotifications(v => !v)} className="btn btn-blue" style={{ gap: 6, height: 40, position: 'relative' }}>
                            <Bell size={15} /> Alerts
                            {notifications.length > 0 && (
                                <span style={{ position: 'absolute', top: -6, right: -6, width: 18, height: 18, background: '#EF4444', borderRadius: 99, fontSize: 9, color: 'white', fontWeight: 900, display: 'flex', alignItems: 'center', justifyContent: 'center', border: '2px solid white' }}>
                                    {notifications.length}
                                </span>
                            )}
                        </button>
                        {showNotifications && (
                            <div className="notif-panel">
                                <div style={{ padding: '14px 16px', borderBottom: '1px solid #F1F5F9', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                    <span style={{ fontWeight: 800, fontSize: 14 }}>Store Notifications</span>
                                    <button onClick={() => setShowNotifications(false)} style={{ background: 'none', border: 'none', cursor: 'pointer' }}><X size={16} color="#94A3B8" /></button>
                                </div>
                                <div style={{ maxHeight: 360, overflowY: 'auto' }}>
                                    {notifications.length === 0 ? (
                                        <div style={{ padding: 20, textAlign: 'center', color: '#94A3B8', fontSize: 13 }}>All clear! No alerts.</div>
                                    ) : notifications.map((n, i) => (
                                        <div key={i} style={{ padding: '10px 16px', borderBottom: '1px solid #F8FAFC', display: 'flex', gap: 10, alignItems: 'flex-start' }}>
                                            <div style={{ width: 28, height: 28, borderRadius: 8, background: n.type === 'new' ? '#DCFCE7' : n.type === 'expired' ? '#FEE2E2' : '#FEF3C7', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0, marginTop: 1 }}>
                                                {n.type === 'new' ? <CheckCircle2 size={14} color="#16A34A" /> : n.type === 'expired' ? <AlertTriangle size={14} color="#DC2626" /> : <Clock size={14} color="#D97706" />}
                                            </div>
                                            <p style={{ fontSize: 12, color: '#374151', lineHeight: 1.4 }}>{n.msg}</p>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            </div>

            {/* Stats */}
            <div className="stores-grid">
                {[
                    { label: 'Total Stores', value: stats.total, icon: Store, bg: '#E0E7FF', color: '#4338CA' },
                    { label: 'Active (7d)', value: stats.active, icon: Wifi, bg: '#DCFCE7', color: '#16A34A' },
                    { label: 'Paid Plans', value: stats.paid, icon: Star, bg: '#FEF3C7', color: '#D97706' },
                    { label: 'New This Week', value: stats.newThisWeek, icon: TrendingUp, bg: '#F3E8FF', color: '#7C3AED' },
                ].map(({ label, value, icon: Icon, bg, color }) => (
                    <div key={label} style={{ background: 'white', borderRadius: 16, padding: '18px 16px', boxShadow: '0 2px 8px rgba(0,0,0,0.04)', border: '1px solid #F1F5F9' }}>
                        <div style={{ width: 42, height: 42, borderRadius: 12, background: bg, display: 'flex', alignItems: 'center', justifyContent: 'center', marginBottom: 10 }}>
                            <Icon size={20} color={color} />
                        </div>
                        <p style={{ fontSize: 11, color: '#64748B', fontWeight: 700 }}>{label}</p>
                        <h3 style={{ fontSize: 26, fontWeight: 900, color: '#0F172A', marginTop: 2 }}>{value}</h3>
                    </div>
                ))}
            </div>

            {/* Search + Filters */}
            <div style={{ display: 'flex', gap: 12, marginBottom: 16, flexWrap: 'wrap' }}>
                <div style={{ position: 'relative', flex: 1, minWidth: 200 }}>
                    <Search style={{ position: 'absolute', left: 12, top: '50%', transform: 'translateY(-50%)', color: '#94A3B8' }} size={15} />
                    <input className="e-input" placeholder="Search by name, email or phone…" value={search} onChange={e => setSearch(e.target.value)} style={{ paddingLeft: 38, height: 40 }} />
                    {search && <button onClick={() => setSearch('')} style={{ position: 'absolute', right: 10, top: '50%', transform: 'translateY(-50%)', background: 'none', border: 'none', cursor: 'pointer' }}><X size={14} color="#94A3B8" /></button>}
                </div>
            </div>

            <div className="filter-bar">
                {(['all', 'active', 'inactive', 'paid', 'free', 'new'] as const).map(f => (
                    <button key={f} onClick={() => setFilter(f)}
                        className={filter === f ? 'btn btn-blue btn-sm' : 'btn btn-outline btn-sm'}
                        style={{ fontSize: 12, height: 34, textTransform: 'capitalize' }}>
                        {f === 'all' ? `All (${stores.length})` : f === 'active' ? `🟢 Active (${stores.filter(s => s.isActive).length})` : f === 'inactive' ? `🔴 Inactive (${stores.filter(s => !s.isActive).length})` : f === 'paid' ? `⭐ Paid (${stores.filter(s => s.plan !== 'free' && s.plan !== 'Free Trial' && s.plan !== 'expired_subscription').length})` : f === 'free' ? `🆓 Free (${stores.filter(s => s.plan === 'free' || s.plan === 'Free Trial').length})` : `🆕 New (${stores.filter(s => s.daysInactive <= 7).length})`}
                    </button>
                ))}
            </div>

            <div style={{ fontSize: 12, color: '#94A3B8', marginBottom: 16 }}>
                Showing <strong style={{ color: '#374151' }}>{filtered.length}</strong> of <strong style={{ color: '#374151' }}>{stores.length}</strong> stores
            </div>

            {/* Store List */}
            {loading ? (
                <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: 200, color: '#64748B' }}>Loading stores…</div>
            ) : filtered.length === 0 ? (
                <div style={{ textAlign: 'center', padding: 48, color: '#94A3B8' }}>
                    <Store size={48} style={{ opacity: 0.3, margin: '0 auto 12px', display: 'block' }} />
                    <p>No stores match your criteria.</p>
                </div>
            ) : (
                <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
                    {filtered.map(store => {
                        const planBadge = getPlanBadge(store.plan);
                        const activityStatus = getActivityStatus(store.daysInactive);
                        const isExpanded = expandedId === store.docId;

                        return (
                            <div key={store.docId} className="store-row">
                                <div className="store-header" onClick={() => setExpandedId(isExpanded ? null : store.docId)}>
                                    {/* Avatar */}
                                    <div style={{ width: 44, height: 44, borderRadius: 12, background: 'linear-gradient(135deg, #1A1A2E, #4285F4)', color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 900, fontSize: 18, flexShrink: 0 }}>
                                        {store.name.charAt(0).toUpperCase()}
                                    </div>

                                    {/* Info */}
                                    <div style={{ flex: 1, minWidth: 0 }}>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: 8, flexWrap: 'wrap' }}>
                                            <p style={{ fontWeight: 800, fontSize: 15, color: '#1A1A2E' }}>{store.name}</p>
                                            <span style={{ padding: '2px 8px', borderRadius: 999, background: planBadge.bg, color: planBadge.color, fontSize: 10, fontWeight: 800 }}>{planBadge.label}</span>
                                        </div>
                                        <div style={{ display: 'flex', gap: 12, marginTop: 4, flexWrap: 'wrap' }}>
                                            <span style={{ fontSize: 11, color: '#64748B', display: 'flex', alignItems: 'center', gap: 3 }}><Mail size={11} />{store.email}</span>
                                            {store.phone !== 'N/A' && <span style={{ fontSize: 11, color: '#64748B', display: 'flex', alignItems: 'center', gap: 3 }}><Phone size={11} />{store.phone}</span>}
                                        </div>
                                    </div>

                                    {/* Stats chips */}
                                    <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap', alignItems: 'center' }}>
                                        <span className="stat-chip" style={{ background: '#F0F9FF', color: '#0369A1' }}><Building2 size={11} />{store.companiesCount}</span>
                                        <span className="stat-chip" style={{ background: '#F0FDF4', color: '#166534' }}><FileText size={11} />{store.invoicesCount}</span>
                                        <span className="stat-chip" style={{ background: activityStatus.color + '18', color: activityStatus.color }}>
                                            {store.isActive ? <Wifi size={11} /> : <WifiOff size={11} />}{activityStatus.label}
                                        </span>
                                        <ChevronDown size={16} color="#94A3B8" style={{ transform: isExpanded ? 'rotate(180deg)' : 'none', transition: 'transform 0.2s' }} />
                                    </div>
                                </div>

                                {/* Expanded */}
                                {isExpanded && (
                                    <div className="expand-section">
                                        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(140px,1fr))', gap: 10, marginBottom: 16 }}>
                                            <div style={{ background: 'white', padding: '12px 14px', borderRadius: 10, border: '1px solid #E2E8F0' }}>
                                                <p style={{ fontSize: 10, color: '#94A3B8', fontWeight: 700, marginBottom: 3 }}>DOC ID</p>
                                                <p style={{ fontSize: 11, fontFamily: 'monospace', color: '#374151', wordBreak: 'break-all' }}>{store.docId}</p>
                                            </div>
                                            <div style={{ background: 'white', padding: '12px 14px', borderRadius: 10, border: '1px solid #E2E8F0' }}>
                                                <p style={{ fontSize: 10, color: '#94A3B8', fontWeight: 700, marginBottom: 3 }}>LAST ACTIVE</p>
                                                <p style={{ fontSize: 12, fontWeight: 700, color: activityStatus.color }}>
                                                    {store.lastActive ? new Date(store.lastActive).toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' }) : 'Unknown'}
                                                </p>
                                            </div>
                                            <div style={{ background: 'white', padding: '12px 14px', borderRadius: 10, border: '1px solid #E2E8F0' }}>
                                                <p style={{ fontSize: 10, color: '#94A3B8', fontWeight: 700, marginBottom: 3 }}>PLAN</p>
                                                <p style={{ fontSize: 12, fontWeight: 800, color: planBadge.color }}>{store.plan}</p>
                                            </div>
                                            <div style={{ background: 'white', padding: '12px 14px', borderRadius: 10, border: '1px solid #E2E8F0' }}>
                                                <p style={{ fontSize: 10, color: '#94A3B8', fontWeight: 700, marginBottom: 3 }}>TOTAL REVENUE</p>
                                                <p style={{ fontSize: 13, fontWeight: 900, color: '#059669' }}>₹{store.revenue.toLocaleString('en-IN')}</p>
                                            </div>
                                        </div>

                                        {/* Companies */}
                                        {store.companies.length > 0 && (
                                            <>
                                                <p style={{ fontSize: 12, fontWeight: 800, color: '#374151', marginBottom: 8 }}>
                                                    <Building2 size={13} style={{ verticalAlign: 'middle', marginRight: 4 }} />
                                                    Companies ({store.companies.length})
                                                </p>
                                                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill,minmax(180px,1fr))', gap: 8 }}>
                                                    {store.companies.map(co => (
                                                        <div key={co.id} style={{ background: 'white', padding: '10px 12px', borderRadius: 10, border: '1px solid #E2E8F0' }}>
                                                            <p style={{ fontWeight: 700, fontSize: 12, color: '#1A1A2E', marginBottom: 2 }}>{co.name}</p>
                                                            <p style={{ fontSize: 10, color: '#94A3B8' }}>{co.type} {co.city ? `• ${co.city}` : ''}</p>
                                                            <p style={{ fontSize: 11, color: '#4285F4', fontWeight: 700, marginTop: 4 }}>{co.invoices} invoices</p>
                                                        </div>
                                                    ))}
                                                </div>
                                            </>
                                        )}

                                        {store.companies.length === 0 && (
                                            <div style={{ background: '#FFFBEB', padding: '10px 14px', borderRadius: 10, border: '1px solid #FDE68A', fontSize: 12, color: '#92400E' }}>
                                                ⚠️ No companies created yet under this account.
                                            </div>
                                        )}
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
            )}
        </div>
    );
}
